mapper.select:
SELECT ci.UserId, ci.ProductId AS CartProductId, ci.Quantity AS CartQuantity,
p.ProductId, p.ProductName, p.Price, p.ImageUrl
FROM CartItems ci JOIN Products p ON ci.ProductId = p.ProductId WHERE ci.UserId = #{userId}

mapper.update:
UPDATE CartItems
SET Quantity = #{quantity}
WHERE UserId = #{userId} AND ProductId = #{productId}
